#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <beaufort.h>
enum { NO_OP, ENCRYPT_OP, DECRYPT_OP };
static void
usage () {
  fprintf(stderr, "usage: beaufort [-hV] [options]\n");
}
static void
help () {
  fprintf(stderr, "\noptions:\n");
  fprintf(stderr, "\n  --encrypt           encrypt stdin stream");
  fprintf(stderr, "\n  --decrypt           decrypt stdin stream");
  fprintf(stderr, "\n  --key=[key]         cipher key (required)");
  fprintf(stderr,
      "\n  --alphabet=[alpha]  cipher tableau alphabet (Default: '%s')\n",
      BEAUFORT_ALPHA);
  fprintf(stderr, "\n");
}
static char *
read_stdin () {
  size_t bsize = 1024;
  size_t size = 1;
  char buf[bsize];
  char *res = (char *) malloc(sizeof(char) * bsize);
  char *tmp = NULL;

  if (NULL == res) { return NULL; }

  res[0] = '\0';

  if (NULL != fgets(buf, bsize, stdin)) {

    tmp = res;

    size += (size_t) strlen(buf);

    res = (char *) realloc(res, size);

    if (NULL == res) {
      free(tmp);
      return NULL;
    }

    strcat(res, buf);
    return res;
  }
  free(res);
  return NULL;
}
int
main (int argc, char **argv) {
  char *buf = NULL;
  char *alpha = NULL;
  char *key = NULL;
  char *out = NULL;
  char **mat = NULL;
  int op = NO_OP;

  if (1 == argc) { return usage(), 1; }

  {
    int i = 0;
    char *opt = NULL;
    char tmp = 0;
    opt = *argv++; 
    while ((opt = *argv++)) {

      if ('-' == *opt++) {
        switch (*opt++) {
          case 'h':
            return usage(), help(), 0;
          case 'V':
            fprintf(stderr, "%s\n", BEAUFORT_VERSION);
            return 0;
          case '-':
            if (0 == strcmp(opt, "encrypt")) { op = ENCRYPT_OP;}
            if (0 == strcmp(opt, "decrypt")) { op = DECRYPT_OP;}

            if (0 == strncmp(opt, "key=", 4)) {
              for (i = 0; i < 4; ++i) tmp = *opt++;
              key = opt;
            }
            if (0 == strncmp(opt, "alphabet=", 8)) {
              for (i = 0; i < 9; ++i) tmp = *opt++;
              alpha = opt;
            }
            break;
          default:
            tmp = *opt--;

            fprintf(stderr, "unknown option: `%s'\n", opt);
            usage();
            return 1;
        }
      }
    }
  }
  if (NULL == alpha) {
    alpha = BEAUFORT_ALPHA;
  }
  mat = beaufort_tableau(alpha);
  if (NULL == key) {
    fprintf(stderr, "error: Expecting cipher key\n");
    usage();
    return 1;
  }
#define OP(name) {                               \
  buf = read_stdin();                            \
  if (NULL == buf) { return 1; }                 \
  out = beaufort_ ## name(buf, key, mat);        \
  printf("%s\n", out);                           \
  do {                                           \
    buf = read_stdin();                          \
    if (NULL == buf) { break; }                  \
    out = beaufort_ ## name(buf, key, mat);      \
    printf("%s\n", out);                         \
  } while (NULL != buf);                         \
}
switch (op) {
  case ENCRYPT_OP:
    if (1 == isatty(0)) { return 1; }
    else if (ferror(stdin)) { return 1; }
    else { OP(encrypt); }
    return 0;
  case DECRYPT_OP:
    if (1 == isatty(0)) { return 1; }
    else if (ferror(stdin)) { return 1; }
    else { OP(decrypt); }
    return 0;
  case NO_OP:
  default:
    return usage(), 1;
}
#undef OP
return 0;
}
